const body = $input.first().json.body;
const message = body.message || '';
const conversationId = body.conversation_id || '';
const callbackUrl = body.callback_url || '';
const context = body.site_context || {};
const user = body.user || {};
const channel = context.channel || 'admin';
const meta = body._meta || {};

// Provider detection from _meta or site_context
const provider = meta.provider || context.ai?.provider || context.ai_provider || 'openai';
const model = meta.model || context.ai?.model || 'gpt-4o-mini';
const maxTokens = meta.max_tokens || context.ai?.max_tokens || 1000;

// API key: from _meta, site_context, or env
let apiKey = '';
if (provider === 'anthropic') {
  apiKey = context.ai?.api_key || meta.api_key || $env.ANTHROPIC_API_KEY || '';
} else if (provider === 'google') {
  apiKey = context.ai?.api_key || meta.api_key || $env.GOOGLE_AI_API_KEY || '';
} else {
  apiKey = context.ai?.api_key || meta.api_key || $env.OPENAI_API_KEY || '';
}

const systemPrompt = `You are Open Claw, an AI assistant for managing WordPress + WooCommerce stores.\n\nStore: ${context.site_name || 'Store'} (${context.site_url || ''})\nProducts: ${context.products || 0} | Posts: ${context.posts || 0}\nSEO Plugin: ${context.seo_plugin || 'none'}\nTranslation: ${context.translation_plugin || 'none'}\nLanguages: ${(context.active_languages || []).join(', ') || 'default'}\nChannel: ${channel}\n\nAvailable actions:\n${Object.entries(context.available_actions || {}).map(([k,v]) => '- ' + k + ': ' + v).join('\n')}\n\nRules:\n- Be concise and helpful\n- Use markdown for formatting\n- For actions, end with JSON: {"action": "type", "params": {}, "confirm": true}\n- Include specific numbers when possible`;

// Build provider-specific request
let apiUrl, headers, requestBody;

if (provider === 'anthropic') {
  apiUrl = 'https://api.anthropic.com/v1/messages';
  headers = { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' };
  requestBody = JSON.stringify({ model, max_tokens: maxTokens, system: systemPrompt, messages: [{ role: 'user', content: message }] });
} else if (provider === 'google') {
  apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;
  headers = { 'Content-Type': 'application/json' };
  requestBody = JSON.stringify({ system_instruction: { parts: [{ text: systemPrompt }] }, contents: [{ role: 'user', parts: [{ text: message }] }], generationConfig: { maxOutputTokens: maxTokens } });
} else {
  // OpenAI (default)
  apiUrl = 'https://api.openai.com/v1/chat/completions';
  headers = { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' };
  requestBody = JSON.stringify({ model, max_tokens: maxTokens, messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: message }] });
}

return [{ json: { message, conversationId, callbackUrl, systemPrompt, channel, provider, model, apiUrl, headers, requestBody } }];

const aiResponse = $input.first().json;
const inputData = $('Build AI Context').first().json;
const provider = inputData.provider || 'openai';

// Extract text based on provider response format
let responseText = '';
try {
  if (provider === 'anthropic') {
    responseText = aiResponse.content?.[0]?.text || '';
  } else if (provider === 'google') {
    responseText = aiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  } else {
    // OpenAI
    responseText = aiResponse.choices?.[0]?.message?.content || '';
  }
} catch (e) {
  responseText = 'Error processing AI response.';
}

if (!responseText) {
  responseText = 'I could not process that request. Please try again.';
}

// Extract action suggestions
let actions = [];
const actionMatch = responseText.match(/\{[\s\S]*?"action"[\s\S]*?\}/);
if (actionMatch) {
  try {
    const actionJson = JSON.parse(actionMatch[0]);
    if (actionJson.action) {
      actions.push({
        type: actionJson.action,
        label: actionJson.label || actionJson.action,
        description: actionJson.description || '',
        data: actionJson.params || {},
        confirm: actionJson.confirm !== false
      });
      responseText = responseText.replace(actionMatch[0], '').trim();
    }
  } catch (e) {}
}

const result = {
  conversation_id: inputData.conversationId,
  response: responseText,
  actions: actions,
  channel: inputData.channel
};

if (inputData.callbackUrl) {
  result.callback_url = inputData.callbackUrl;
}

return [{ json: result }];

const data = $('Parse Response').first().json;
return [{
  json: {
    success: true,
    response: data.response,
    actions: data.actions,
    conversation_id: data.conversation_id
  }
}];
